import React, { useEffect, useState } from 'react';
import { useNavigate } from 'react-router-dom';
import axios from 'axios';
import './PostProduct.css';

function PostProduct() {
  const navigate = useNavigate();
  const [categories, setCategories] = useState([]);
  const [user, setUser] = useState(null);
  const [form, setForm] = useState({
    name: '',
    description: '',
    price: '',
    image_url: '',
    category_id: '',
  });
  const [message, setMessage] = useState('');
  const [error, setError] = useState('');
  const [loading, setLoading] = useState(false);

  useEffect(() => {
    // Check if user is logged in and has verified company
    const token = localStorage.getItem('token');
    const userData = localStorage.getItem('user');

    if (!token || !userData) {
      navigate('/login');
      return;
    }

    const parsedUser = JSON.parse(userData);
    setUser(parsedUser);

    if (!parsedUser.has_company) {
      // Redirect to register company
      navigate('/register-company');
      return;
    }

    if (!parsedUser.company_verified) {
      setError('Your company is pending verification. Please register your company and wait for admin approval. Once approved, you will be able to post products and access the Seller Dashboard.');
    }

    const fetchData = async () => {
      try {
        const catRes = await axios.get('/api/categories');
        setCategories(catRes.data);
      } catch (err) {
        console.error('Error loading form data', err);
      }
    };
    fetchData();
  }, [navigate]);

  const handleChange = (key, value) => {
    setForm((prev) => ({ ...prev, [key]: value }));
  };

  const handleSubmit = async (e) => {
    e.preventDefault();
    setError('');
    setMessage('');
    setLoading(true);
    try {
      const token = localStorage.getItem('token');
      const user = JSON.parse(localStorage.getItem('user'));

      const payload = {
        ...form,
        price: form.price ? Number(form.price) : null,
        user_id: user.id
      };

      await axios.post('/api/post-product', payload, {
        headers: { Authorization: `Bearer ${token}` }
      });

      setMessage('Product posted successfully!');
      setForm({
        name: '',
        description: '',
        price: '',
        image_url: '',
        category_id: '',
      });
    } catch (err) {
      setError(err.response?.data?.error || 'Failed to post product');
    } finally {
      setLoading(false);
    }
  };

  return (
    <div className="post-product-page">
      <div className="container">
        <div className="post-card">
          <h1>Post a Product</h1>
          <p className="post-subtitle">Reach thousands of buyers on DealsDouble.ai</p>
          {message && <div className="success">{message}</div>}
          {error && (
            <div className="error">
              {error}
              {!user?.has_company && (
                <button
                  onClick={() => navigate('/register-company')}
                  className="mt-4 px-4 py-2 rounded-lg bg-gradient-to-r from-accent-purple to-accent-pink text-white hover:opacity-90 transition-opacity"
                >
                  Register Your Company Now
                </button>
              )}
            </div>
          )}

          <form onSubmit={handleSubmit} className="post-form">
            <div className="input-group">
              <label>Product Name</label>
              <input
                type="text"
                required
                value={form.name}
                onChange={(e) => handleChange('name', e.target.value)}
              />
            </div>

            <div className="input-group">
              <label>Description</label>
              <textarea
                required
                value={form.description}
                onChange={(e) => handleChange('description', e.target.value)}
              />
            </div>

            <div className="input-row">
              <div className="input-group">
                <label>Price (₹)</label>
                <input
                  type="number"
                  value={form.price}
                  onChange={(e) => handleChange('price', e.target.value)}
                />
              </div>
              <div className="input-group">
                <label>Image URL</label>
                <input
                  type="text"
                  value={form.image_url}
                  onChange={(e) => handleChange('image_url', e.target.value)}
                />
              </div>
            </div>

            <div className="input-group">
              <label>Category</label>
              <select
                required
                value={form.category_id}
                onChange={(e) => handleChange('category_id', e.target.value)}
              >
                <option value="">Select category</option>
                {categories.map((c) => (
                  <option key={c.id} value={c.id}>{c.name}</option>
                ))}
              </select>
            </div>

            <button type="submit" className="btn btn-primary" disabled={loading || !!error}>
              {loading ? 'Posting...' : 'Submit'}
            </button>
          </form>
        </div>
      </div>
    </div>
  );
}

export default PostProduct;
